solution_code:
#include <iostream>

void printBorder()
{
    std::cout << "========\n";
}

void printItems()
{
    std::cout << "Item 1\n";
    std::cout << "Item 2\n";
}

void printDone()
{
    std::cout << "Done.\n";
}

int main()
{
    printBorder();
    printItems();
    printBorder();
    printDone();
    return 0;
}

